  "max_tokens": {{ $env.AI_MAX_TOKENS || 4096 }},
  "messages": [
    {
      "role": "user",
      "content": "You are a senior software architect performing technical analysis for a development team.

Given the following feature description, produce a detailed technical analysis as a JSON object.

## Feature Description
{{ $json.featureDescription }}

## Additional Context
{{ $json.additionalContext }}

## Output Format

Respond ONLY with valid JSON matching this schema:

{
  "title": "Short descriptive title",
  "summary": "2-3 sentence executive summary",
  "architecture": {
    "overview": "High-level architecture description",
    "components": [{"name": "...", "type": "frontend|backend|database|infrastructure", "description": "...", "changes": "..."}],
    "dataFlow": "Data flow description"
  },
  "apiContracts": [{"method": "GET|POST|PUT|DELETE", "path": "/api/...", "description": "...", "requestBody": {}, "responseBody": {}, "statusCodes": ["200 - OK"]}],
  "databaseChanges": [{"type": "new-table|alter-table", "entity": "...", "description": "...", "fields": [{"name": "...", "type": "...", "nullable": false}]}],
  "edgeCases": [{"scenario": "...", "impact": "low|medium|high", "mitigation": "..."}],
  "securityConsiderations": ["..."],
  "testingStrategy": {"unitTests": ["..."], "integrationTests": ["..."], "e2eTests": ["..."]},
  "tasks": [{"type": "epic|story|subtask", "summary": "...", "description": "...", "component": "frontend|backend|database|devops|testing", "estimate": "XS|S|M|L|XL", "priority": "Critical|High|Medium|Low", "acceptanceCriteria": ["Given X, when Y, then Z"]}],
  "estimatedComplexity": "low|medium|high",
  "suggestedApproach": "Recommended implementation order"
}

Rules: Tasks should be 1-3 day work items. Include Gherkin acceptance criteria. Be specific, not generic."
    }
  ]
}

parameters.jsCode:
// Extract JSON from Claude's response
const response = $input.first().json;
const content = response.content[0].text;

// Parse the JSON (handle markdown code fences if present)
let jsonStr = content;
if (content.includes('```json')) {
  jsonStr = content.split('```json')[1].split('```')[0].trim();
} else if (content.includes('```')) {
  jsonStr = content.split('```')[1].split('```')[0].trim();
}

let analysis;
try {
  analysis = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse AI response as JSON: ${e.message}\n\nRaw response: ${content.substring(0, 500)}`);
}

// Get variables from earlier node
const vars = $('Set Variables').first().json;

return [{
  json: {
    analysis,
    featureDescription: vars.featureDescription,
    createJiraTasks: vars.createJiraTasks,
    confluenceParentPageId: vars.confluenceParentPageId
  }
}];

// Convert analysis JSON to Confluence-friendly HTML
const { analysis } = $input.first().json;

let html = '';

// Summary
html += `<h2>Summary</h2><p>${analysis.summary}</p>`;

// Architecture
html += `<h2>Architecture</h2>`;
html += `<p>${analysis.architecture.overview}</p>`;
html += `<h3>Components</h3>`;
html += `<table><thead><tr><th>Component</th><th>Type</th><th>Description</th><th>Changes</th></tr></thead><tbody>`;
for (const c of analysis.architecture.components || []) {
  html += `<tr><td><strong>${c.name}</strong></td><td><code>${c.type}</code></td><td>${c.description}</td><td>${c.changes}</td></tr>`;
}
html += `</tbody></table>`;

if (analysis.architecture.dataFlow) {
  html += `<h3>Data Flow</h3><p>${analysis.architecture.dataFlow}</p>`;
}

// API Contracts
if (analysis.apiContracts?.length) {
  html += `<h2>API Contracts</h2>`;
  for (const api of analysis.apiContracts) {
    html += `<h3><code>${api.method} ${api.path}</code></h3>`;
    html += `<p>${api.description}</p>`;
    if (api.requestBody && Object.keys(api.requestBody).length) {
      html += `<p><strong>Request:</strong></p><ac:structured-macro ac:name="code"><ac:parameter ac:name="language">json</ac:parameter><ac:plain-text-body><![CDATA[${JSON.stringify(api.requestBody, null, 2)}]]></ac:plain-text-body></ac:structured-macro>`;
    }
    if (api.responseBody && Object.keys(api.responseBody).length) {
      html += `<p><strong>Response:</strong></p><ac:structured-macro ac:name="code"><ac:parameter ac:name="language">json</ac:parameter><ac:plain-text-body><![CDATA[${JSON.stringify(api.responseBody, null, 2)}]]></ac:plain-text-body></ac:structured-macro>`;
    }
    if (api.statusCodes?.length) {
      html += `<p><strong>Status Codes:</strong> ${api.statusCodes.join(', ')}</p>`;
    }
  }
}

// Database Changes
if (analysis.databaseChanges?.length) {
  html += `<h2>Database Changes</h2>`;
  html += `<table><thead><tr><th>Type</th><th>Entity</th><th>Description</th></tr></thead><tbody>`;
  for (const db of analysis.databaseChanges) {
    html += `<tr><td><code>${db.type}</code></td><td><strong>${db.entity}</strong></td><td>${db.description}</td></tr>`;
    if (db.fields?.length) {
      html += `<tr><td colspan="3"><table><thead><tr><th>Field</th><th>Type</th><th>Nullable</th><th>Description</th></tr></thead><tbody>`;
      for (const f of db.fields) {
        html += `<tr><td><code>${f.name}</code></td><td><code>${f.type}</code></td><td>${f.nullable ? 'Yes' : 'No'}</td><td>${f.description || ''}</td></tr>`;
      }
      html += `</tbody></table></td></tr>`;
    }
  }
  html += `</tbody></table>`;
}

// Edge Cases
if (analysis.edgeCases?.length) {
  html += `<h2>Edge Cases</h2>`;
  html += `<table><thead><tr><th>Scenario</th><th>Impact</th><th>Mitigation</th></tr></thead><tbody>`;
  for (const ec of analysis.edgeCases) {
    html += `<tr><td>${ec.scenario}</td><td><code>${ec.impact}</code></td><td>${ec.mitigation}</td></tr>`;
  }
  html += `</tbody></table>`;
}

// Security
if (analysis.securityConsiderations?.length) {
  html += `<h2>Security Considerations</h2><ul>`;
  for (const s of analysis.securityConsiderations) {
    html += `<li>${s}</li>`;
  }
  html += `</ul>`;
}

// Testing Strategy
if (analysis.testingStrategy) {
  html += `<h2>Testing Strategy</h2>`;
  const ts = analysis.testingStrategy;
  if (ts.unitTests?.length) {
    html += `<h3>Unit Tests</h3><ul>${ts.unitTests.map(t => `<li>${t}</li>`).join('')}</ul>`;
  }
  if (ts.integrationTests?.length) {
    html += `<h3>Integration Tests</h3><ul>${ts.integrationTests.map(t => `<li>${t}</li>`).join('')}</ul>`;
  }
  if (ts.e2eTests?.length) {
    html += `<h3>E2E Tests</h3><ul>${ts.e2eTests.map(t => `<li>${t}</li>`).join('')}</ul>`;
  }
}

// Tasks Summary
if (analysis.tasks?.length) {
  html += `<h2>Task Breakdown</h2>`;
  html += `<table><thead><tr><th>Type</th><th>Summary</th><th>Component</th><th>Estimate</th><th>Priority</th></tr></thead><tbody>`;
  for (const t of analysis.tasks) {
    html += `<tr><td><code>${t.type}</code></td><td>${t.summary}</td><td><code>${t.component}</code></td><td>${t.estimate}</td><td>${t.priority}</td></tr>`;
  }
  html += `</tbody></table>`;
}

// Complexity & Approach
html += `<h2>Overall</h2>`;
html += `<p><strong>Estimated Complexity:</strong> ${analysis.estimatedComplexity}</p>`;
html += `<p><strong>Suggested Approach:</strong> ${analysis.suggestedApproach}</p>`;

// Metadata footer
html += `<hr/><p><em>Generated by <a href="https://github.com/openmindednewby/ai-confluence-pipeline">ai-confluence-pipeline</a> on ${new Date().toISOString().split('T')[0]}</em></p>`;

return [{ json: { html, title: analysis.title, analysis: $input.first().json.analysis, createJiraTasks: $input.first().json.createJiraTasks, confluenceParentPageId: $input.first().json.confluenceParentPageId } }];

// Extract tasks from analysis and prepare for Jira
const analysis = $('Parse AI Response').first().json.analysis;
const confluencePage = $('Create Confluence Page').first().json;
const confluenceUrl = confluencePage._links?.base + confluencePage._links?.webui;

const tasks = analysis.tasks || [];

// Map estimates to story points
const estimateToPoints = { 'XS': 1, 'S': 2, 'M': 3, 'L': 5, 'XL': 8 };

return tasks.map(task => ({
  json: {
    task,
    storyPoints: estimateToPoints[task.estimate] || 3,
    confluenceUrl,
    pageTitle: analysis.title
  }
}));

