={
  "fields": {
    "project": { "key": "{{ $env.JIRA_PROJECT_KEY }}" },
    "summary": "{{ $json.task.summary }}",
    "description": {
      "type": "doc",
      "version": 1,
      "content": [
        {
          "type": "paragraph",
          "content": [{ "type": "text", "text": {{ JSON.stringify($json.task.description) }} }]
        },
        {
          "type": "heading",
          "attrs": { "level": 3 },
          "content": [{ "type": "text", "text": "Acceptance Criteria" }]
        },
        {
          "type": "bulletList",
          "content": {{ JSON.stringify(($json.task.acceptanceCriteria || []).map(ac => ({ "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": ac }] }] }))) }}
        },
        {
          "type": "paragraph",
          "content": [
            { "type": "text", "text": "Technical Analysis: " },
            { "type": "text", "text": {{ JSON.stringify($json.pageTitle) }}, "marks": [{ "type": "link", "attrs": { "href": {{ JSON.stringify($json.confluenceUrl || '') }} } }] }
          ]
        }
      ]
    },
    "issuetype": { "name": "{{ $json.task.type === 'epic' ? ($env.JIRA_EPIC_ISSUE_TYPE || 'Epic') : $json.task.type === 'subtask' ? ($env.JIRA_SUBTASK_ISSUE_TYPE || 'Sub-task') : ($env.JIRA_STORY_ISSUE_TYPE || 'Story') }}" },
    "priority": { "name": "{{ $json.task.priority || $env.JIRA_DEFAULT_PRIORITY || 'Medium' }}" },
    "labels": ["n8n-pipeline-generated", "{{ $json.task.component }}"]
  }
}

