// Aggregate results
const confluencePage = $('Create Confluence Page').first().json;
const analysis = $('Parse AI Response').first().json.analysis;
const jiraIssues = $input.all().map(item => item.json);

return [{
  json: {
    success: true,
    confluencePage: {
      id: confluencePage.id,
      title: confluencePage.title,
      url: (confluencePage._links?.base || '') + (confluencePage._links?.webui || '')
    },
    jiraIssues: jiraIssues.map(issue => ({
      key: issue.key,
      summary: issue.fields?.summary,
      url: `${process.env.JIRA_BASE_URL}/browse/${issue.key}`
    })),
    taskCount: jiraIssues.length,
    complexity: analysis.estimatedComplexity
  }
}];

// No Jira tasks — just return Confluence result
const confluencePage = $('Create Confluence Page').first().json;
const analysis = $('Parse AI Response').first().json.analysis;

return [{
  json: {
    success: true,
    confluencePage: {
      id: confluencePage.id,
      title: confluencePage.title,
      url: (confluencePage._links?.base || '') + (confluencePage._links?.webui || '')
    },
    jiraIssues: [],
    taskCount: 0,
    complexity: analysis.estimatedComplexity,
    note: 'Jira task creation was skipped (createJiraTasks=false)'
  }
}];
